class TreeNode {
  val: number;
  left: TreeNode | null;
  right: TreeNode | null;
  constructor(val: number = 0, left: TreeNode | null = null, right: TreeNode | null = null) {
    this.val = val; this.left = left; this.right = right;
  }
}

function hasPathSum(node: TreeNode | null, target: number): boolean {
  if (node === null) return false;
  if (node.left === null && node.right === null) return node.val === target;
  return hasPathSum(node.left, target - node.val) || hasPathSum(node.right, target - node.val);
}

const root = new TreeNode(5, new TreeNode(4, new TreeNode(2), null), new TreeNode(8, new TreeNode(3), null));
console.log(hasPathSum(root, 11));  // true (5->4->2)
console.log(hasPathSum(root, 20));  // false

